/**
 * client/src/App.js
 * Root component: sets up React Router v6 and TanStack Query.
 */

import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import { Toaster } from 'react-hot-toast';

import Layout from './components/Layout';
import Dashboard from './pages/Dashboard';
import FriendDetail from './pages/FriendDetail';
import FriendForm from './pages/FriendForm';

// Configure TanStack Query: cache data for 5 minutes, retry once on failure
const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      staleTime: 1000 * 60 * 5,
      retry: 1,
      refetchOnWindowFocus: false,
    },
  },
});

export default function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <BrowserRouter>
        <Toaster
          position="top-right"
          toastOptions={{
            duration: 3500,
            style: { borderRadius: '8px', fontSize: '14px' },
          }}
        />
        <Routes>
          <Route element={<Layout />}>
            <Route index element={<Dashboard />} />
            <Route path="friends/new" element={<FriendForm />} />
            <Route path="friends/:id" element={<FriendDetail />} />
            <Route path="friends/:id/edit" element={<FriendForm />} />
          </Route>
          {/* Catch-all redirect */}
          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </BrowserRouter>
    </QueryClientProvider>
  );
}
